import * as fs from 'fs';
import * as path from 'path';
import { fileURLToPath } from 'url';
import { execSync } from 'child_process';
import { AcousticEngine } from '../../aether/src/acoustic-siphon';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

async function main() {
  const sentence = process.argv[2] || "Stew";
  const voiceName = process.argv[3] || "Sophia";

  console.log('============================================================');
  console.log(` ARTICULATORY SYNTHESIS: "${sentence}" (Voice: ${voiceName})`);
  console.log('============================================================\n');

  const sequence = textToPhonemeSequence(sentence);
  const gnosisMathDir = path.resolve(__dirname, '../../../gnosis-math');
  const scoreFile = sentence.toLowerCase() === 'stew' ? 'stew-score.json' : 'gestural-score.json';
  const scorePath = path.join(__dirname, scoreFile);

  console.log('[1. COMPILER] Reading Pre-compiled Gestural Score...');
  const score = JSON.parse(fs.readFileSync(scorePath, 'utf8'));
  console.log(`[2. PHYSICS] Loaded Task Dynamics with ${score.tongueHeight.length} physical targets.`);

  const engine = new AcousticEngine();
  engine.setVoice(voiceName);

  console.log('[3. WAVEGUIDE] Executing Digital Waveguide Scattering (Kelly-Lochbaum)...');
  const audio = await engine.synthesize(score);

  // Save and Play
  const outputWav = path.join(__dirname, 'hard-science-output.wav');
  const int16Buffer = new Int16Array(audio.length);
  for (let i = 0; i < audio.length; i++) {
    // Waveguide output is naturally low amplitude, apply normalization boost
    int16Buffer[i] = Math.max(-32768, Math.min(32767, audio[i] * 32767 * 20)); 
  }
  
  writeWav(outputWav, int16Buffer, 24000);
  console.log('\n[✔] SUCCESS: Physical wave exhaled to ' + outputWav);
  
  try {
    execSync('afplay ' + outputWav);
  } catch (e) {}
}

function textToPhonemeSequence(text: string): string[] {
  if (text.toLowerCase() === "stew") return ['S', 'T', 'UW', 'SIL'];
  if (text.toLowerCase() === "coin") return ['K', 'OY', 'N', 'SIL'];
  return ['SIL'];
}

function writeWav(filename: string, samples: Int16Array, sampleRate: number) {
  const buffer = Buffer.alloc(44 + samples.length * 2);
  buffer.write('RIFF', 0);
  buffer.writeUInt32LE(36 + samples.length * 2, 4);
  buffer.write('WAVE', 8);
  buffer.write('fmt ', 12);
  buffer.writeUInt32LE(16, 16);
  buffer.writeUInt16LE(1, 20);
  buffer.writeUInt16LE(1, 22);
  buffer.writeUInt32LE(sampleRate, 24);
  buffer.writeUInt32LE(sampleRate * 2, 28);
  buffer.writeUInt16LE(2, 32);
  buffer.writeUInt16LE(16, 34);
  buffer.write('data', 36);
  buffer.writeUInt32LE(samples.length * 2, 40);
  for (let i = 0; i < samples.length; i++) {
    buffer.writeInt16LE(samples[i], 44 + i * 2);
  }
  fs.writeFileSync(filename, buffer);
}

main().catch(console.error);